  var pp_link = 'https://paypal.me/ISKCONCommunications/';
  var radios = form['reg_amt'];

  for (i = 0; i < radios.length; i++) {
    if (radios[i].checked) {
      donation_selected = true;
      donation_amount = radios[i].value;

      if (donation_amount < 0) {
        $('#step2').show();
        $('#pp_button').hide();
      } else {
        pp_link += donation_amount;
        $('#pp_button').show();
        $('#step2').hide();
      }
    }
  }

